    data: {
      projectId: string;
      modelId: string;
      videosCount: number;
      notes?: string;
    },
    options?: { actorId?: string; actorName?: string }
  ) {
    // Check for duplicate assignment
    const existing = await modelRepository.findAssignment(data.projectId, data.modelId);
    if (existing) {
      throw new Error("الموديل مُعيّن بالفعل في هذا المشروع");
    }

    // Calculate pricing
    const { pricePerVideo, totalAmount } = calculatePricing(data.videosCount);

    const assignment = await modelRepository.createAssignment({
      projectId: data.projectId,
      modelId: data.modelId,
      videosCount: data.videosCount,
      pricePerVideo,
      totalAmount,
      notes: data.notes || null,
    });

    // Publish timeline event
    await timelineService.publish({
      projectId: data.projectId,
      eventType: "MODEL_ASSIGNED",
      title: "تعيين موديل",
      description: `تم تعيين ${assignment.model.fullName} (${assignment.model.modelCode}) بـ ${data.videosCount} فيديو`,
      metadata: {
        modelId: data.modelId,
        modelCode: assignment.model.modelCode,
        videosCount: data.videosCount,
        totalAmount,
      },
      actorId: options?.actorId,
      actorName: options?.actorName ?? "النظام",
    });

    // Activity log
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "CREATE",
        entity: "project_model",
        entityId: assignment.id,
        metadata: { projectId: data.projectId, modelId: data.modelId },
      });
    }

    return assignment;
  },

  async updateAssignment(
    id: string,
    data: {
      videosCount: number;
      paymentStatus?: PaymentStatus;
      notes?: string;
    },
    options?: { actorId?: string; actorName?: string }
  ) {
    // Recalculate pricing
    const { pricePerVideo, totalAmount } = calculatePricing(data.videosCount);

    const assignment = await modelRepository.updateAssignment(id, {
      videosCount: data.videosCount,
      pricePerVideo,
      totalAmount,
      paymentStatus: data.paymentStatus,
      notes: data.notes || null,
    });

    // Publish timeline events
    await timelineService.publish({
      projectId: (assignment as never as { projectId: string }).projectId,
      eventType: "MODEL_VIDEOS_UPDATED",
      title: "تحديث فيديوهات الموديل",
      description: `تم تحديث عدد الفيديوهات إلى ${data.videosCount} — الإجمالي: ${totalAmount}`,
      metadata: { assignmentId: id, videosCount: data.videosCount, totalAmount },
      actorId: options?.actorId,
      actorName: options?.actorName ?? "النظام",
    });

    if (data.paymentStatus) {
      await timelineService.publish({
        projectId: (assignment as never as { projectId: string }).projectId,
        eventType: "MODEL_PAYMENT_UPDATED",
        title: "تحديث حالة الدفع",
        description: `حالة الدفع: ${data.paymentStatus}`,
        metadata: { assignmentId: id, paymentStatus: data.paymentStatus },
        actorId: options?.actorId,
        actorName: options?.actorName ?? "النظام",
      });
    }

    return assignment;
  },

  async removeFromProject(
    id: string,
    options?: { actorId?: string; actorName?: string }
  ) {
    const assignment = await modelRepository.deleteAssignment(id);

    // Publish timeline event
    await timelineService.publish({
      projectId: (assignment as never as { projectId: string }).projectId,
      eventType: "MODEL_REMOVED",
      title: "إزالة موديل",
      description: `تمت إزالة الموديل من المشروع`,
      metadata: { assignmentId: id, modelId: (assignment as never as { modelId: string }).modelId },
      actorId: options?.actorId,
      actorName: options?.actorName ?? "النظام",
    });

    return assignment;
  },

  async getAssignmentsByProject(projectId: string) {
    return modelRepository.findAssignmentsByProject(projectId);
  },

  async getDashboardStats() {
    return modelRepository.getDashboardStats();
  },
};

import { prisma } from "@/lib/prisma";
import type { Prisma, ClientStatus } from "@prisma/client";

/* ============================================
   Client Repository
   The ONLY layer that interacts with Prisma
   for Client operations.
   ============================================ */

export type ClientWithRelations = Prisma.ClientGetPayload<{
  include: {
    projects: true;
    _count: {
      select: {
        projects: true;
        downloads: true;
        views: true;
      };
    };
  };
}>;

export type ClientCreateInput = Prisma.ClientUncheckedCreateInput;
export type ClientUpdateInput = Prisma.ClientUncheckedUpdateInput;
export type ClientWhereInput = Prisma.ClientWhereInput;
export type ClientWhereUniqueInput = Prisma.ClientWhereUniqueInput;

/** Build the WHERE clause for search + filter. */
function buildWhere(params: {
  userId: string;
  search?: string;
  filter?: "all" | "active" | "archived" | "blocked";
}): ClientWhereInput {
  const where: ClientWhereInput = { userId: params.userId };

  // Soft-delete: archived clients excluded from default queries
  if (params.filter === "archived") {
    where.status = "ARCHIVED";
  } else if (params.filter === "active") {
    where.status = "ACTIVE";
  } else if (params.filter === "blocked") {
    where.status = "BLOCKED";
  } else {
    // "all" — exclude archived by default unless explicitly filtered
    where.status = { not: "ARCHIVED" };
  }

  if (params.search) {
    where.OR = [
      { clientCode: { contains: params.search, mode: "insensitive" } },
      { name: { contains: params.search, mode: "insensitive" } },
      { company: { contains: params.search, mode: "insensitive" } },
      { phone: { contains: params.search, mode: "insensitive" } },
      { email: { contains: params.search, mode: "insensitive" } },
    ];
  }

  return where;
}

/** Build the ORDER BY clause for sorting. */
function buildOrderBy(sort: "newest" | "oldest" | "alphabetical") {
  if (sort === "oldest") return { createdAt: "asc" as const };
  if (sort === "alphabetical") return { name: "asc" as const };
  return { createdAt: "desc" as const };
}

export const clientRepository = {
  findById(id: string) {
    return prisma.client.findUnique({
      where: { id },
      include: {
        projects: true,
        _count: {
          select: {
            projects: true,
            downloads: true,
            views: true,
          },
        },
      },
    });
  },

  findByClientCode(clientCode: string) {
    return prisma.client.findUnique({
      where: { clientCode },
      include: { projects: true },
    });
  },

  findByToken(token: string) {
    return prisma.client.findUnique({
      where: { token },
      include: { projects: true },
    });
  },

  findByEmail(userId: string, email: string) {
    return prisma.client.findUnique({
      where: { userId_email: { userId, email } },
    });
  },

  create(data: ClientCreateInput) {
    return prisma.client.create({
      data,
      include: {
        projects: true,
        _count: {
          select: {
            projects: true,
            downloads: true,
            views: true,
          },
        },
      },
    });
  },

  update(id: string, data: ClientUpdateInput) {
    return prisma.client.update({
      where: { id },
      data,
      include: {
        projects: true,
        _count: {
          select: {
            projects: true,
            downloads: true,
            views: true,
          },
        },
      },
    });
  },

  /** Soft delete — set status to ARCHIVED and archivedAt. */
  softDelete(id: string) {
    return prisma.client.update({
      where: { id },
      data: {
        status: "ARCHIVED" as ClientStatus,
        archivedAt: new Date(),
      },
    });
  },

  /** Restore an archived client. */
  restore(id: string) {
    return prisma.client.update({
      where: { id },
      data: {
        status: "ACTIVE" as ClientStatus,
        archivedAt: null,
      },
    });
  },

  /** Hard delete — used only in tests/cleanup, never in production. */
  delete(id: string) {
    return prisma.client.delete({ where: { id } });
  },

  /** Paginated list with search, filter, and sort. */
  async findMany(params: {
    userId: string;
    skip?: number;
    take?: number;
    search?: string;
    filter?: "all" | "active" | "archived" | "blocked";
    sort?: "newest" | "oldest" | "alphabetical";
  }) {
    const where = buildWhere(params);
    const orderBy = buildOrderBy(params.sort ?? "newest");

    const [items, total] = await Promise.all([
      prisma.client.findMany({
        where,
        skip: params.skip,
        take: params.take,
        orderBy,
        include: {
          _count: {
            select: {
              projects: true,
            },
          },
        },
      }),
      prisma.client.count({ where }),
    ]);

    return { items, total };
  },

  count(where?: ClientWhereInput) {
    return prisma.client.count({ where });
  },

  /** Count all clients for code generation. */
  countAll() {
    return prisma.client.count();
  },

  /** Find the latest client code for sequential generation. */
  findLatestClientCode() {
    return prisma.client.findFirst({
      orderBy: { clientCode: "desc" },
      select: { clientCode: true },
    });
  },

  /** Get statistics for a client. */
  async getStatistics(clientId: string) {
    const [projects, downloads, views] = await Promise.all([
      prisma.project.count({ where: { clientId } }),
      prisma.download.count({ where: { clientId } }),
      prisma.view.count({ where: { clientId } }),
    ]);

    // Videos are nested under projects
    const projectIds = await prisma.project.findMany({
      where: { clientId },
      select: { id: true },
    });
    const videos = await prisma.video.count({
      where: { projectId: { in: projectIds.map((p) => p.id) } },
    });

    return { projects, videos, downloads, views };
  },

  /** Export all clients (non-archived) as flat rows for CSV. */
  async findAllForExport(userId: string) {
    return prisma.client.findMany({
      where: {
        userId,
        status: { not: "ARCHIVED" },
      },
      orderBy: { createdAt: "desc" },
      include: {
        _count: {
          select: { projects: true },
        },
      },
    });
  },
};

import { prisma } from "@/lib/prisma";
import type { Prisma, ProjectStatus } from "@prisma/client";

/* ============================================
   Project Repository
   The ONLY layer that interacts with Prisma
   for Project operations.
   ============================================ */

export type ProjectWithRelations = Prisma.ProjectGetPayload<{
  include: { client: true; videos: true };
}>;

export type ProjectCreateInput = Prisma.ProjectUncheckedCreateInput;
export type ProjectUpdateInput = Prisma.ProjectUncheckedUpdateInput;
export type ProjectWhereInput = Prisma.ProjectWhereInput;
export type ProjectWhereUniqueInput = Prisma.ProjectWhereUniqueInput;

/** Map filter values to Prisma status conditions. */
function statusFromFilter(
  filter: string
): Prisma.ProjectWhereInput["status"] | undefined {
  const map: Record<string, string> = {
    draft: "DRAFT",
    in_progress: "IN_PROGRESS",
    ready: "READY",
    download_enabled: "DOWNLOAD_ENABLED",
    completed: "COMPLETED",
    archived: "ARCHIVED",
  };
  return map[filter] as Prisma.ProjectWhereInput["status"] | undefined;
}

/** Build the WHERE clause for search + filter. */
function buildWhere(params: {
  clientId?: string;
  search?: string;
  filter?: string;
}): ProjectWhereInput {
  const where: ProjectWhereInput = {};

  // Soft-delete: archived projects excluded from default queries
  if (params.filter === "archived") {
    where.status = "ARCHIVED";
  } else if (params.filter && params.filter !== "all") {
    where.status = statusFromFilter(params.filter);
  } else {
    // "all" — exclude archived by default
    where.status = { not: "ARCHIVED" };
  }

  if (params.clientId) {
    where.clientId = params.clientId;
  }

  if (params.search) {
    where.OR = [
      { projectCode: { contains: params.search, mode: "insensitive" } },
      { name: { contains: params.search, mode: "insensitive" } },
      { client: { name: { contains: params.search, mode: "insensitive" } } },
    ];
  }

  return where;
}

/** Build the ORDER BY clause for sorting. */
function buildOrderBy(sort: string): Prisma.ProjectOrderByWithRelationInput {
  if (sort === "oldest") return { createdAt: "asc" };
  if (sort === "deadline") return { deadline: "asc" };
  if (sort === "alphabetical") return { name: "asc" };
  return { createdAt: "desc" };
}

