    filter: params?.filter ?? "all",
    sort: params?.sort ?? "newest",
  });

  const totalPages = Math.ceil(total / pageSize);

  return {
    items: items.map((m) => ({
      id: m.id,
      modelCode: m.modelCode,
      fullName: m.fullName,
      phone: m.phone,
      whatsapp: m.whatsapp,
      email: m.email,
      photo: m.photo,
      status: m.status,
      notes: m.notes,
      createdAt: m.createdAt,
      updatedAt: m.updatedAt,
      projectCount: m._count.projectModels,
    })),
    total,
    page,
    pageSize,
    totalPages,
  };
}

